using System.IO.Compression;
using System.Text;
class ZipCreator
{
    void CreateArchive()
    {
        // .NET 9 breaking change: ZipArchiveEntry now sets the UTF-8 flag for
        // non-ASCII names. The legacy Java consumer reads Shift-JIS, so we must
        // specify the encoding explicitly to suppress the UTF-8 flag.
        Encoding.RegisterProvider(CodePagesEncodingProvider.Instance);
        var shiftJis = Encoding.GetEncoding("shift_jis");

        using var archive = ZipFile.Open("data.zip", ZipArchiveMode.Create, shiftJis);
        archive.CreateEntry("Ńā¼ŃāØŃā╝Ńāł/µ£łµ¼Ī.csv");  // Japanese path
        archive.CreateEntry("donn├®es/r├®sum├®.txt"); // French accented
    }
}

// .NET 9 breaking change: [FromKeyedServices] no longer falls back to
// non-keyed registrations. Register as keyed to match the controller attribute.
